using System;
using System.Windows.Forms;

public class Calculator : Form
{
    private TextBox input1;
    private TextBox input2;
    private TextBox result;
    private Button addButton;
    private Button subtractButton;
    private Button multiplyButton;
    private Button divideButton;

    public Calculator()
    {
        // Initialize UI components
        input1 = new TextBox { Location = new System.Drawing.Point(10, 10) };
        input2 = new TextBox { Location = new System.Drawing.Point(10, 40) };
        result = new TextBox { Location = new System.Drawing.Point(10, 70) };
        addButton = new Button { Text = "+", Location = new System.Drawing.Point(10, 100) };
        subtractButton = new Button { Text = "-", Location = new System.Drawing.Point(50, 100) };
        multiplyButton = new Button { Text = "*", Location = new System.Drawing.Point(90, 100) };
        divideButton = new Button { Text = "/", Location = new System.Drawing.Point(130, 100) };

        // Add event handlers
        addButton.Click += (sender, e) => Calculate(input1.Text, input2.Text, "+");
        subtractButton.Click += (sender, e) => Calculate(input1.Text, input2.Text, "-");
        multiplyButton.Click += (sender, e) => Calculate(input1.Text, input2.Text, "*");
        divideButton.Click += (sender, e) => Calculate(input1.Text, input2.Text, "/");

        // Add UI components to the form
        Controls.Add(input1);
        Controls.Add(input2);
        Controls.Add(result);
        Controls.Add(addButton);
        Controls.Add(subtractButton);
        Controls.Add(multiplyButton);
        Controls.Add(divideButton);
    }

    private void Calculate(string num1, string num2, string operation)
    {
        try
        {
            double resultValue = 0;
            switch (operation)
            {
                case "+":
                    resultValue = double.Parse(num1) + double.Parse(num2);
                    break;
                case "-":
                    resultValue = double.Parse(num1) - double.Parse(num2);
                    break;
                case "*":
                    resultValue = double.Parse(num1) * double.Parse(num2);
                    break;
                case "/":
                    resultValue = double.Parse(num1) / double.Parse(num2);
                    break;
            }
            result.Text = resultValue.ToString();
        }
        catch (Exception ex)
        {
            MessageBox.Show("Error: " + ex.Message);
        }
    }

    [STAThread]
    static void Main()
    {
        Application.EnableVisualStyles();
        Application.SetCompatibleTextRenderingDefault(false);
        Application.Run(new Calculator());
    }
}
```
